import{_ as t,o as a,c as n,a0 as s}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Event Templates & Instances Explained","description":"","frontmatter":{},"headers":[],"relativePath":"events/templates-overview.md","filePath":"events/templates-overview.md"}'),l={name:"events/templates-overview.md"};function i(r,e,o,h,c,p){return a(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="event-templates-instances-explained" tabindex="-1">Event Templates &amp; Instances Explained <a class="header-anchor" href="#event-templates-instances-explained" aria-label="Permalink to &quot;Event Templates &amp; Instances Explained&quot;">​</a></h1><p>Event work in Kingshot Event Tracker starts with two layers:</p><ul><li>an <strong>event template</strong>, which defines how an event works</li><li>an <strong>event instance</strong>, which is one real run of that event on real dates</li></ul><p>If you are new to these terms, read <a href="./../getting-started/what-is-the-tracker.html">What the Tracker Does</a> and the <a href="./../getting-started/glossary.html">Glossary</a> first. This page goes deeper on how event pages are used day to day.</p><blockquote><p>Screenshot placeholder: events-templates.png</p></blockquote><h2 id="the-simple-difference" tabindex="-1">The simple difference <a class="header-anchor" href="#the-simple-difference" aria-label="Permalink to &quot;The simple difference&quot;">​</a></h2><p>Think of a template as the rulebook and an instance as the match.</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;Event template&quot;] --&gt; B[&quot;Event instance&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;Manual rows or imports&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;Saved results, analytics, and rewards&quot;]</span></span></code></pre></div><ul><li>A <strong>template</strong> decides things like score label, whether the event uses stages, whether totals are cumulative, and which import options appear.</li><li>An <strong>instance</strong> is the dated occurrence you actually work inside.</li><li>Results, analytics, and reward checks happen on the <strong>instance</strong>, not on the template itself.</li></ul><h2 id="what-templates-control" tabindex="-1">What templates control <a class="header-anchor" href="#what-templates-control" aria-label="Permalink to &quot;What templates control&quot;">​</a></h2><p>An event template can control:</p><ul><li>the event name, icon, colors, and description</li><li>whether the event is single-session, multi-day, or multi-stage</li><li>whether scores are entered as one score, a cumulative total, or daily changes</li><li>whether score is required, optional, or mostly irrelevant</li><li>whether the event appears in dashboards and analytics</li><li>membership and eligibility rules for who counts in the instance</li></ul><p>These settings shape future imports and future instances. They are not meant to rewrite old history.</p><h2 id="what-instances-control" tabindex="-1">What instances control <a class="header-anchor" href="#what-instances-control" aria-label="Permalink to &quot;What instances control&quot;">​</a></h2><p>An instance is where you set:</p><ul><li>the start and end dates</li><li>the current stage, if the event uses stages</li><li>stage dates, if needed</li><li>the actual imported or manual result rows</li><li>lock and unlock state after the event ends</li></ul><p>Open <strong>Event Instances</strong> when you want to create or manage real dated runs.</p><h2 id="common-event-patterns" tabindex="-1">Common event patterns <a class="header-anchor" href="#common-event-patterns" aria-label="Permalink to &quot;Common event patterns&quot;">​</a></h2><p>The app currently uses three main event patterns:</p><ul><li><strong>Single-session</strong> events such as Bear Trap and Viking Vengeance</li><li><strong>Multi-day cumulative</strong> events such as Alliance Mobilization</li><li><strong>Multi-stage</strong> events such as Alliance Brawl, Kingdom of Power, and Strongest Governor</li></ul><p>Sanctuary Battle is a special case: it is mainly a participation and control-tracking event, not a normal score race. See <a href="./sanctuary-battle.html">Sanctuary Battle</a>.</p><h2 id="default-templates-and-custom-templates" tabindex="-1">Default templates and custom templates <a class="header-anchor" href="#default-templates-and-custom-templates" aria-label="Permalink to &quot;Default templates and custom templates&quot;">​</a></h2><p>The tracker starts with seven seeded default templates. See <a href="./default-events.html">The Default Events</a> for the list.</p><p>Important:</p><ul><li>default templates can be edited</li><li>default templates can be customized into kingdom or alliance versions</li><li>default templates cannot be deleted</li></ul><p>That protection rule is explained in <a href="./../roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a>.</p><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="./default-events.html">The Default Events</a></li><li><a href="./../how-to/create-custom-event.html">Create a Custom Event</a></li><li><a href="./../how-to/edit-event-template.html">Edit an Event Template</a></li><li><a href="./../how-to/create-instance.html">Create an Event Instance</a></li></ul>`,28)])])}const m=t(l,[["render",i]]);export{u as __pageData,m as default};
